 * Abre o Finder e Terminal lado a lado, sincronizados
 */

import { $ } from "bun";

async function setupSideBySide() {
  console.log("🔧 Configurando Finder + Terminal lado a lado...\n");

  // AppleScript para posicionar Finder e Terminal lado a lado
  const script = `
    tell application "Finder"
      activate
      if (count of windows) = 0 then
        make new Finder window
      end if

      set finderWindow to front window
      set bounds of finderWindow to {0, 25, 900, 700}
    end tell

    tell application "Terminal"
      activate
      if (count of windows) = 0 then
        do script ""
      end if

      set terminalWindow to front window
      set bounds of terminalWindow to {900, 25, 1500, 700}
    end tell

    -- Trazer Finder para frente mas manter Terminal visível
    tell application "Finder" to activate
  `;

  try {
    await $`osascript -e ${script}`;
    console.log("✅ Janelas posicionadas lado a lado!");
    console.log("\n📍 Finder: esquerda | Terminal: direita\n");
  } catch (e) {
    console.error("❌ Erro:", e);
  }
}

setupSideBySide();

