import SwiftUI

struct FileListView: View {
    @EnvironmentObject var appState: AppState
    @State private var files: [FileItem] = []
    @State private var sortOrder: SortOrder = .name
    @State private var sortAscending = true

    enum SortOrder {
        case name, date, size
    }

    var body: some View {
        VStack(spacing: 0) {
            // Header
            HStack {
                HeaderButton(title: "Name", sortOrder: .name, current: $sortOrder, ascending: $sortAscending)
                    .frame(maxWidth: .infinity, alignment: .leading)

                HeaderButton(title: "Date Modified", sortOrder: .date, current: $sortOrder, ascending: $sortAscending)
                    .frame(width: 150, alignment: .leading)

                HeaderButton(title: "Size", sortOrder: .size, current: $sortOrder, ascending: $sortAscending)
                    .frame(width: 80, alignment: .trailing)
            }
            .padding(.horizontal, 16)
            .padding(.vertical, 8)
            .background(Color(NSColor.controlBackgroundColor))

            Divider()

            // File list
            ScrollView {
                LazyVStack(spacing: 0) {
                    ForEach(sortedFiles) { file in
                        FileRow(file: file, isSelected: appState.selectedItems.contains(file.url))
                            .onTapGesture {
                                handleTap(file)
                            }
                            .onTapGesture(count: 2) {
                                handleDoubleTap(file)
                            }
                    }
                }
            }
        }
        .background(Color(NSColor.controlBackgroundColor))
        .onAppear { loadFiles() }
        .onChange(of: appState.currentPath) { _, _ in loadFiles() }
    }

    private var sortedFiles: [FileItem] {
        let sorted: [FileItem]
        switch sortOrder {
        case .name:
            sorted = files.sorted { $0.name.localizedCaseInsensitiveCompare($1.name) == .orderedAscending }
        case .date:
            sorted = files.sorted { ($0.modificationDate ?? .distantPast) < ($1.modificationDate ?? .distantPast) }
        case .size:
            sorted = files.sorted { ($0.size ?? 0) < ($1.size ?? 0) }
        }
        return sortAscending ? sorted : sorted.reversed()
    }

    private func loadFiles() {
        do {
            let urls = try FileManager.default.contentsOfDirectory(
                at: appState.currentPath,
                includingPropertiesForKeys: [.isDirectoryKey, .fileSizeKey, .contentModificationDateKey],
                options: [.skipsHiddenFiles]
            )
            files = urls.map { FileItem(url: $0) }
        } catch {
            files = []
        }
    }

    private func handleTap(_ file: FileItem) {
        if NSEvent.modifierFlags.contains(.command) {
            if appState.selectedItems.contains(file.url) {
                appState.selectedItems.remove(file.url)
            } else {
                appState.selectedItems.insert(file.url)
            }
        } else {
            appState.selectedItems = [file.url]
        }
    }

    private func handleDoubleTap(_ file: FileItem) {
        if file.isDirectory {
            appState.navigateTo(file.url)
        } else {
            NSWorkspace.shared.open(file.url)
        }
    }
}

struct HeaderButton: View {
    let title: String
    let sortOrder: FileListView.SortOrder
    @Binding var current: FileListView.SortOrder
    @Binding var ascending: Bool

    var body: some View {
        Button(action: {
            if current == sortOrder {
                ascending.toggle()
            } else {
                current = sortOrder
                ascending = true
            }
        }) {
            HStack(spacing: 4) {
                Text(title)
                    .font(.system(size: 11, weight: .medium))
                if current == sortOrder {
                    Image(systemName: ascending ? "chevron.up" : "chevron.down")
                        .font(.system(size: 9))
                }
            }
            .foregroundColor(.secondary)
        }
        .buttonStyle(.plain)
    }
}

