import Foundation

/// Manages a pseudo-terminal (PTY) for running shell commands
class PseudoTerminal: ObservableObject {
    private var masterFD: Int32 = -1
    private var slaveFD: Int32 = -1
    private var shellPID: pid_t = 0
    private var readSource: DispatchSourceRead?

    @Published var output: String = ""
    @Published var isRunning: Bool = false

    var currentDirectory: URL {
        didSet {
            // Send cd command when directory changes externally
            if isRunning && currentDirectory != oldValue {
                sendCommand("cd \"\(currentDirectory.path)\"")
            }
        }
    }

    var onDirectoryChange: ((URL) -> Void)?

    init(directory: URL = FileManager.default.homeDirectoryForCurrentUser) {
        self.currentDirectory = directory
    }

    deinit {
        stop()
    }

    /// Start the pseudo-terminal with a shell
    func start() {
        guard !isRunning else { return }

        // Open PTY
        var master: Int32 = 0
        var slave: Int32 = 0

        if openpty(&master, &slave, nil, nil, nil) == -1 {
            output += "Error: Failed to open PTY\r\n"
            return
        }

        masterFD = master
        slaveFD = slave

        // Fork process
        let pid = fork()

        if pid == -1 {
            output += "Error: Failed to fork process\r\n"
            close(masterFD)
            close(slaveFD)
            return
        }

        if pid == 0 {
            // Child process
            close(masterFD)

            // Create new session
            setsid()

            // Set controlling terminal
            ioctl(slaveFD, TIOCSCTTY, 0)

            // Redirect stdio
            dup2(slaveFD, STDIN_FILENO)
            dup2(slaveFD, STDOUT_FILENO)
            dup2(slaveFD, STDERR_FILENO)

            if slaveFD > STDERR_FILENO {
                close(slaveFD)
            }

            // Change to initial directory
            chdir(currentDirectory.path)

            // Set environment
            setenv("TERM", "xterm-256color", 1)
            setenv("HOME", FileManager.default.homeDirectoryForCurrentUser.path, 1)

            // Get user's shell
            let shell = getenv("SHELL").map { String(cString: $0) } ?? "/bin/zsh"

            // Execute shell
            execl(shell, shell, "-l", nil)

            // If exec fails
            _exit(1)
        }

        // Parent process
        close(slaveFD)
        shellPID = pid
        isRunning = true

        // Start reading output
        startReading()
    }

