import Foundation
import AppKit

struct FileItem: Identifiable, Hashable {
    let id: URL
    let url: URL
    let name: String
    let isDirectory: Bool
    let size: Int64?
    let modificationDate: Date?
    let icon: NSImage

    init(url: URL) {
        self.id = url
        self.url = url
        self.name = url.lastPathComponent

        var isDir: ObjCBool = false
        FileManager.default.fileExists(atPath: url.path, isDirectory: &isDir)
        self.isDirectory = isDir.boolValue

        if let attributes = try? FileManager.default.attributesOfItem(atPath: url.path) {
            self.size = attributes[.size] as? Int64
            self.modificationDate = attributes[.modificationDate] as? Date
        } else {
            self.size = nil
            self.modificationDate = nil
        }

        self.icon = NSWorkspace.shared.icon(forFile: url.path)
    }

    var formattedSize: String {
        guard let size = size, !isDirectory else { return "--" }
        return ByteCountFormatter.string(fromByteCount: size, countStyle: .file)
    }

    var formattedDate: String {
        guard let date = modificationDate else { return "--" }
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short
        return formatter.string(from: date)
    }

    func hash(into hasher: inout Hasher) {
        hasher.combine(url)
    }

    static func == (lhs: FileItem, rhs: FileItem) -> Bool {
        lhs.url == rhs.url
    }
}

struct SidebarItem: Identifiable {
    let id = UUID()
    let name: String
    let icon: String
    let url: URL?

    static var favorites: [SidebarItem] {
        let home = FileManager.default.homeDirectoryForCurrentUser
        return [
            SidebarItem(name: "Desktop", icon: "menubar.dock.rectangle", url: home.appendingPathComponent("Desktop")),
            SidebarItem(name: "Documents", icon: "doc.fill", url: home.appendingPathComponent("Documents")),
            SidebarItem(name: "Downloads", icon: "arrow.down.circle.fill", url: home.appendingPathComponent("Downloads")),
            SidebarItem(name: "Applications", icon: "square.grid.2x2.fill", url: URL(fileURLWithPath: "/Applications")),
        ]
    }

    static var locations: [SidebarItem] {
        [
            SidebarItem(name: NSHost.current().localizedName ?? "Mac", icon: "desktopcomputer", url: URL(fileURLWithPath: "/")),
            SidebarItem(name: "Home", icon: "house.fill", url: FileManager.default.homeDirectoryForCurrentUser),
        ]
    }
}

