import Foundation

/// Manages a pseudo-terminal (PTY) for running shell commands using Process
class PseudoTerminal: ObservableObject {
    private var process: Process?
    private var masterFileHandle: FileHandle?
    private var slaveFileHandle: FileHandle?
    private var masterFD: Int32 = -1

    @Published var output: String = ""
    @Published var isRunning: Bool = false

    var currentDirectory: URL {
        didSet {
            if isRunning && currentDirectory != oldValue {
                sendCommand("cd \"\(currentDirectory.path)\"")
            }
        }
    }

    var onDirectoryChange: ((URL) -> Void)?

    init(directory: URL = FileManager.default.homeDirectoryForCurrentUser) {
        self.currentDirectory = directory
    }

    deinit {
        stop()
    }

    /// Start the pseudo-terminal with a shell
    func start() {
        guard !isRunning else { return }

        // Open PTY pair
        var master: Int32 = 0
        var slave: Int32 = 0

        guard openpty(&master, &slave, nil, nil, nil) == 0 else {
            output += "Error: Failed to open PTY\r\n"
            return
        }

        masterFD = master

        // Create file handles
        masterFileHandle = FileHandle(fileDescriptor: master, closeOnDealloc: false)
        slaveFileHandle = FileHandle(fileDescriptor: slave, closeOnDealloc: false)

        // Setup process
        let proc = Process()

        // Get user's shell
        let shell = ProcessInfo.processInfo.environment["SHELL"] ?? "/bin/zsh"
        proc.executableURL = URL(fileURLWithPath: shell)
        proc.arguments = ["-l"] // Login shell
        proc.currentDirectoryURL = currentDirectory

        // Set environment
        var env = ProcessInfo.processInfo.environment
        env["TERM"] = "xterm-256color"
        env["LC_ALL"] = "en_US.UTF-8"
        proc.environment = env

        // Use the slave PTY for stdio
        proc.standardInput = slaveFileHandle
        proc.standardOutput = slaveFileHandle
        proc.standardError = slaveFileHandle

        // Start reading from master
        startReading()

        do {
            try proc.run()
            process = proc
            isRunning = true

            // Close slave in parent - child has it
            close(slave)

        } catch {
            output += "Error: \(error.localizedDescription)\r\n"
            close(master)
            close(slave)
        }
    }

    /// Stop the pseudo-terminal
    func stop() {
        guard isRunning else { return }

        process?.terminate()
        process = nil

        if masterFD >= 0 {
            close(masterFD)
            masterFD = -1
        }

        masterFileHandle = nil
        slaveFileHandle = nil
        isRunning = false
    }

    /// Send a command to the shell
    func sendCommand(_ command: String) {
        guard isRunning else { return }

        let data = (command + "\n").data(using: .utf8)!
        try? masterFileHandle?.write(contentsOf: data)

        // Track directory changes
        parseDirectoryChange(from: command)
    }

    /// Send raw input (for interactive use)
    func sendInput(_ input: String) {
        guard isRunning else { return }

        if let data = input.data(using: .utf8) {
            try? masterFileHandle?.write(contentsOf: data)
        }
    }

    /// Send special key
    func sendSpecialKey(_ key: SpecialKey) {
        sendInput(key.ansiSequence)
    }

    private func startReading() {
        guard let handle = masterFileHandle else { return }

        // Read in background
        DispatchQueue.global(qos: .userInteractive).async { [weak self] in
            while self?.isRunning == true {
                let data = handle.availableData

                if data.isEmpty {
                    break
                }

                if let str = String(data: data, encoding: .utf8) {
                    DispatchQueue.main.async {
                        self?.output += str
                    }
                }
            }
        }
    }

    private func parseDirectoryChange(from command: String) {
        let trimmed = command.trimmingCharacters(in: .whitespaces)

        if trimmed.hasPrefix("cd ") || trimmed == "cd" {
            var path = String(trimmed.dropFirst(3)).trimmingCharacters(in: .whitespaces)

            if path.isEmpty {
                path = "~"
            }

            var resolvedPath: String

            if path.hasPrefix("~") {
                resolvedPath = path.replacingOccurrences(
                    of: "~",
                    with: FileManager.default.homeDirectoryForCurrentUser.path
                )
            } else if path.hasPrefix("/") {
                resolvedPath = path
            } else if path == "-" {
                // cd - goes to previous directory, skip tracking
                return
            } else {
                resolvedPath = currentDirectory.appendingPathComponent(path).path
            }

            // Resolve .. and . components
            let url = URL(fileURLWithPath: resolvedPath).standardized

            var isDirectory: ObjCBool = false
            if FileManager.default.fileExists(atPath: url.path, isDirectory: &isDirectory),
               isDirectory.boolValue {
                DispatchQueue.main.asyncAfter(deadline: .now() + 0.15) { [weak self] in
                    guard let self = self else { return }
                    self.currentDirectory = url
                    self.onDirectoryChange?(url)
                }
            }
        }
    }

    /// Clear the terminal output
    func clear() {
        output = ""
        sendInput("\u{000C}") // Ctrl+L
    }

    /// Resize the terminal
    func resize(columns: Int, rows: Int) {
        guard masterFD >= 0 else { return }

        var size = winsize()
        size.ws_col = UInt16(columns)
        size.ws_row = UInt16(rows)
        _ = ioctl(masterFD, TIOCSWINSZ, &size)
    }
}

enum SpecialKey {
    case enter
    case tab
    case backspace
    case delete
    case escape
    case up
    case down
    case left
    case right
    case ctrlC
    case ctrlD
    case ctrlZ
    case ctrlL

    var ansiSequence: String {
        switch self {
        case .enter: return "\r"
        case .tab: return "\t"
        case .backspace: return "\u{7F}"
        case .delete: return "\u{1B}[3~"
        case .escape: return "\u{1B}"
        case .up: return "\u{1B}[A"
        case .down: return "\u{1B}[B"
        case .left: return "\u{1B}[D"
        case .right: return "\u{1B}[C"
        case .ctrlC: return "\u{03}"
        case .ctrlD: return "\u{04}"
        case .ctrlZ: return "\u{1A}"
        case .ctrlL: return "\u{0C}"
        }
    }
}

