    /// Start the pseudo-terminal with a shell
    func start() {
        guard !isRunning else { return }

        // Open PTY
        var master: Int32 = 0
        var slave: Int32 = 0

        if openpty(&master, &slave, nil, nil, nil) == -1 {
            output += "Error: Failed to open PTY\r\n"
            return
        }

        masterFD = master
        slaveFD = slave

        // Fork process
        let pid = fork()

        if pid == -1 {
            output += "Error: Failed to fork process\r\n"
            close(masterFD)
            close(slaveFD)
            return
        }

        if pid == 0 {
            // Child process
            close(masterFD)

            // Create new session
            setsid()

            // Set controlling terminal
            ioctl(slaveFD, TIOCSCTTY, 0)

            // Redirect stdio
            dup2(slaveFD, STDIN_FILENO)
            dup2(slaveFD, STDOUT_FILENO)
            dup2(slaveFD, STDERR_FILENO)

            if slaveFD > STDERR_FILENO {
                close(slaveFD)
            }

            // Change to initial directory
            chdir(currentDirectory.path)

            // Set environment
            setenv("TERM", "xterm-256color", 1)
            setenv("HOME", FileManager.default.homeDirectoryForCurrentUser.path, 1)

            // Get user's shell
            let shell = getenv("SHELL").map { String(cString: $0) } ?? "/bin/zsh"

            // Execute shell
            execl(shell, shell, "-l", nil)

            // If exec fails
            _exit(1)
        }

        // Parent process
        close(slaveFD)
        shellPID = pid
        isRunning = true

        // Start reading output
        startReading()
    }

    /// Stop the pseudo-terminal
    func stop() {
        guard isRunning else { return }

        readSource?.cancel()
        readSource = nil

        if shellPID > 0 {
            kill(shellPID, SIGTERM)
            var status: Int32 = 0
            waitpid(shellPID, &status, 0)
            shellPID = 0
        }

        if masterFD >= 0 {
            close(masterFD)
            masterFD = -1
        }

        isRunning = false
    }

    /// Send a command to the shell
    func sendCommand(_ command: String) {
        guard isRunning, masterFD >= 0 else { return }

        let data = command + "\n"
        data.withCString { ptr in
            write(masterFD, ptr, strlen(ptr))
        }

        // Check if it's a cd command to track directory changes
        parseDirectoryChange(from: command)
    }

    /// Send raw input (for interactive use)
    func sendInput(_ input: String) {
        guard isRunning, masterFD >= 0 else { return }

        input.withCString { ptr in
            write(masterFD, ptr, strlen(ptr))
        }
    }

    /// Send special key
    func sendSpecialKey(_ key: SpecialKey) {
        guard isRunning, masterFD >= 0 else { return }

        let sequence = key.ansiSequence
        sequence.withCString { ptr in
            write(masterFD, ptr, strlen(ptr))
        }
    }

    private func startReading() {
        let source = DispatchSource.makeReadSource(fileDescriptor: masterFD, queue: .main)

        source.setEventHandler { [weak self] in
            self?.readOutput()
        }

        source.setCancelHandler { [weak self] in
            if let fd = self?.masterFD, fd >= 0 {
                close(fd)
            }
        }

        source.resume()
        readSource = source
    }

    private func readOutput() {
        var buffer = [UInt8](repeating: 0, count: 4096)
        let bytesRead = read(masterFD, &buffer, buffer.count - 1)

        if bytesRead > 0 {
            buffer[bytesRead] = 0
            if let str = String(bytes: buffer[0..<bytesRead], encoding: .utf8) {
                DispatchQueue.main.async { [weak self] in
                    self?.output += str
                    self?.parseOutputForDirectory(str)
                }
            }
        }
    }

    private func parseDirectoryChange(from command: String) {
        let trimmed = command.trimmingCharacters(in: .whitespaces)

        if trimmed.hasPrefix("cd ") {
            let path = String(trimmed.dropFirst(3)).trimmingCharacters(in: .whitespaces)
            var resolvedPath: String

            if path.hasPrefix("~") {
                resolvedPath = path.replacingOccurrences(of: "~", with: FileManager.default.homeDirectoryForCurrentUser.path)
            } else if path.hasPrefix("/") {
                resolvedPath = path
            } else {
                resolvedPath = currentDirectory.appendingPathComponent(path).path
            }

            // Resolve .. and .
            let url = URL(fileURLWithPath: resolvedPath).standardized

            if FileManager.default.fileExists(atPath: url.path) {
                DispatchQueue.main.asyncAfter(deadline: .now() + 0.1) { [weak self] in
                    self?.currentDirectory = url
                    self?.onDirectoryChange?(url)
                }
            }
        }
    }

    private func parseOutputForDirectory(_ output: String) {
        // Could parse PWD from prompt if needed
    }

    /// Clear the terminal output
    func clear() {
        output = ""
        sendInput("\u{000C}") // Ctrl+L
    }

    /// Resize the terminal
    func resize(columns: Int, rows: Int) {
        guard masterFD >= 0 else { return }

        var size = winsize()
        size.ws_col = UInt16(columns)
        size.ws_row = UInt16(rows)
        ioctl(masterFD, TIOCSWINSZ, &size)
    }
}

enum SpecialKey {
    case enter
    case tab
    case backspace
    case delete
    case escape
    case up
    case down
    case left
    case right
    case ctrlC
    case ctrlD
    case ctrlZ
    case ctrlL

    var ansiSequence: String {
        switch self {
        case .enter: return "\r"
        case .tab: return "\t"
        case .backspace: return "\u{7F}"
        case .delete: return "\u{1B}[3~"
        case .escape: return "\u{1B}"
        case .up: return "\u{1B}[A"
        case .down: return "\u{1B}[B"
        case .left: return "\u{1B}[D"
        case .right: return "\u{1B}[C"
        case .ctrlC: return "\u{03}"
        case .ctrlD: return "\u{04}"
        case .ctrlZ: return "\u{1A}"
        case .ctrlL: return "\u{0C}"
        }
    }
}

