import SwiftUI
import AppKit

struct TerminalView: View {
    @EnvironmentObject var appState: AppState
    @StateObject private var terminal = PseudoTerminal()
    @State private var inputText: String = ""
    @FocusState private var isInputFocused: Bool

    var body: some View {
        VStack(spacing: 0) {
            // Terminal header
            HStack {
                Text(appState.currentPath.path)
                    .font(.system(size: 11, weight: .medium, design: .monospaced))
                    .foregroundColor(.secondary)
                    .lineLimit(1)
                    .truncationMode(.head)

                Spacer()

                Button(action: { terminal.clear() }) {
                    Image(systemName: "trash")
                        .font(.system(size: 11))
                }
                .buttonStyle(.plain)
                .help("Clear terminal")
            }
            .padding(.horizontal, 12)
            .padding(.vertical, 8)
            .background(Color(NSColor.controlBackgroundColor))

            Divider()

            // Terminal output
            ScrollViewReader { proxy in
                ScrollView {
                    Text(terminal.output)
                        .font(.system(size: 12, design: .monospaced))
                        .foregroundColor(.primary)
                        .frame(maxWidth: .infinity, alignment: .leading)
                        .textSelection(.enabled)
                        .padding(12)
                        .id("terminalOutput")
                }
                .background(Color(NSColor.textBackgroundColor))
                .onChange(of: terminal.output) { _, _ in
                    withAnimation {
                        proxy.scrollTo("terminalOutput", anchor: .bottom)
                    }
                }
            }

            Divider()

            // Input field
            HStack(spacing: 8) {
                Text("$")
                    .font(.system(size: 12, weight: .bold, design: .monospaced))
                    .foregroundColor(.green)

                TerminalTextField(
                    text: $inputText,
                    onSubmit: submitCommand,
                    onSpecialKey: handleSpecialKey
                )
                .font(.system(size: 12, design: .monospaced))
                .focused($isInputFocused)
            }
            .padding(.horizontal, 12)
            .padding(.vertical, 8)
            .background(Color(NSColor.controlBackgroundColor))
        }
        .onAppear {
            setupTerminal()
            isInputFocused = true
        }
        .onDisappear {
            terminal.stop()
        }
        .onChange(of: appState.currentPath) { _, newPath in
            terminal.currentDirectory = newPath
        }
    }

    private func setupTerminal() {
        terminal.currentDirectory = appState.currentPath
        terminal.onDirectoryChange = { newPath in
            appState.navigateTo(newPath)
        }
        terminal.start()
    }

    private func submitCommand() {
        let command = inputText.trimmingCharacters(in: .whitespaces)
        guard !command.isEmpty else { return }

        terminal.sendCommand(command)
        inputText = ""
    }

    private func handleSpecialKey(_ key: SpecialKey) {
        terminal.sendSpecialKey(key)
    }
}

// Custom TextField that handles special keys
struct TerminalTextField: NSViewRepresentable {
    @Binding var text: String
    var onSubmit: () -> Void
    var onSpecialKey: (SpecialKey) -> Void

    func makeNSView(context: Context) -> NSTextField {
        let textField = NSTextField()
        textField.delegate = context.coordinator
        textField.isBordered = false
        textField.backgroundColor = .clear
        textField.focusRingType = .none
        textField.font = NSFont.monospacedSystemFont(ofSize: 12, weight: .regular)
        return textField
    }

    func updateNSView(_ nsView: NSTextField, context: Context) {
        if nsView.stringValue != text {
            nsView.stringValue = text
        }
    }

    func makeCoordinator() -> Coordinator {
        Coordinator(self)
    }

    class Coordinator: NSObject, NSTextFieldDelegate {
        var parent: TerminalTextField
        private var commandHistory: [String] = []
        private var historyIndex: Int = -1

        init(_ parent: TerminalTextField) {
            self.parent = parent
        }

        func controlTextDidChange(_ obj: Notification) {
            if let textField = obj.object as? NSTextField {
                parent.text = textField.stringValue
            }
        }

        func control(_ control: NSControl, textView: NSTextView, doCommandBy commandSelector: Selector) -> Bool {
            if commandSelector == #selector(NSResponder.insertNewline(_:)) {
                if !parent.text.isEmpty {
                    commandHistory.append(parent.text)
                    historyIndex = commandHistory.count
                }
                parent.onSubmit()
                return true
            }

            if commandSelector == #selector(NSResponder.moveUp(_:)) {
                if historyIndex > 0 {
                    historyIndex -= 1
                    parent.text = commandHistory[historyIndex]
                }
                return true
            }

            if commandSelector == #selector(NSResponder.moveDown(_:)) {
                if historyIndex < commandHistory.count - 1 {
                    historyIndex += 1
                    parent.text = commandHistory[historyIndex]
                } else {
                    historyIndex = commandHistory.count
                    parent.text = ""
                }
                return true
            }

            if commandSelector == #selector(NSResponder.cancelOperation(_:)) {
                parent.onSpecialKey(.ctrlC)
                parent.text = ""
                return true
            }

            return false
        }
    }
}

