export interface FileEntry {
  name: string;
  path: string;
  isDirectory: boolean;
  isFile: boolean;
  isSymlink: boolean;
  size?: number;
  modifiedAt?: Date;
}

export interface SidebarItem {
  name: string;
  path: string;
  icon: string;
}

import { useState, useCallback } from 'react';
import { readDir, stat } from '@tauri-apps/plugin-fs';
import { invoke } from '@tauri-apps/api/core';
import { homeDir } from '@tauri-apps/api/path';
import type { FileEntry } from '../types';

export function useFileSystem() {
  const [currentPath, setCurrentPath] = useState<string>('');
  const [files, setFiles] = useState<FileEntry[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const loadDirectory = useCallback(async (path: string) => {
    setLoading(true);
    setError(null);

    try {
      const entries = await readDir(path);

      const fileEntries: FileEntry[] = await Promise.all(
        entries.map(async (entry) => {
          const fullPath = `${path}/${entry.name}`;
          try {
            const info = await stat(fullPath);
            return {
              name: entry.name,
              path: fullPath,
              isDirectory: info.isDirectory,
              isFile: info.isFile,
              isSymlink: info.isSymlink,
              size: info.size,
              modifiedAt: info.mtime ? new Date(info.mtime) : undefined,
            };
          } catch {
            return {
              name: entry.name,
              path: fullPath,
              isDirectory: entry.isDirectory ?? false,
              isFile: entry.isFile ?? false,
              isSymlink: entry.isSymlink ?? false,
            };
          }
        })
      );

      // Sort: directories first, then by name
      fileEntries.sort((a, b) => {
        if (a.isDirectory && !b.isDirectory) return -1;
        if (!a.isDirectory && b.isDirectory) return 1;
        return a.name.localeCompare(b.name);
      });

      // Filter hidden files
      const visibleFiles = fileEntries.filter(f => !f.name.startsWith('.'));

      setFiles(visibleFiles);
      setCurrentPath(path);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load directory');
      setFiles([]);
    } finally {
      setLoading(false);
    }
  }, []);

  const navigateTo = useCallback((path: string) => {
    loadDirectory(path);
  }, [loadDirectory]);

  const navigateUp = useCallback(() => {
    const parentPath = currentPath.split('/').slice(0, -1).join('/') || '/';
    loadDirectory(parentPath);
  }, [currentPath, loadDirectory]);

  const goHome = useCallback(async () => {
    try {
      const home = await homeDir();
      loadDirectory(home);
    } catch {
      loadDirectory('/');
    }
  }, [loadDirectory]);

  const refresh = useCallback(() => {
    if (currentPath) {
      loadDirectory(currentPath);
    }
  }, [currentPath, loadDirectory]);

  return {
    currentPath,
    files,
    loading,
    error,
    navigateTo,
    navigateUp,
    goHome,
    refresh,
    setCurrentPath,
  };
}

