import { useMemo } from 'react';
import Table from '@jetbrains/ring-ui/components/table/table';
import Selection from '@jetbrains/ring-ui/components/table/selection';
import type { FileEntry } from '../types';

interface FileListProps {
  files: FileEntry[];
  loading: boolean;
  onFileOpen: (file: FileEntry) => void;
  onSelectionChange?: (selected: FileEntry[]) => void;
}

const columns = [
  {
    id: 'name',
    title: 'Name',
    sortable: true,
    getValue: (item: FileEntry) => item.name,
  },
  {
    id: 'modified',
    title: 'Date Modified',
    sortable: true,
    getValue: (item: FileEntry) => {
      if (!item.modifiedAt) return '--';
      return item.modifiedAt.toLocaleDateString('en-US', {
        day: 'numeric',
        month: 'short',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
      });
    },
  },
  {
    id: 'size',
    title: 'Size',
    sortable: true,
    rightAlign: true,
    getValue: (item: FileEntry) => {
      if (item.isDirectory) return '--';
      if (!item.size) return '--';
      return formatBytes(item.size);
    },
  },
];

function formatBytes(bytes: number): string {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
}

export function FileList({ files, loading, onFileOpen, onSelectionChange }: FileListProps) {
  const selection = useMemo(() => new Selection({ data: files }), [files]);

  const data = useMemo(() => {
    return files.map(file => ({
      ...file,
      id: file.path,
      key: file.path,
      icon: file.isDirectory ? '📁' : '📄',
    }));
  }, [files]);

  const handleSelect = (selected: Selection) => {
    if (onSelectionChange) {
      const selectedItems = selected.getSelected() as FileEntry[];
      onSelectionChange(selectedItems);
    }
  };

  const handleRowDoubleClick = (item: FileEntry) => {
    onFileOpen(item);
  };

  if (loading) {
    return (
      <div style={{ padding: '20px', textAlign: 'center', color: '#888' }}>
        Loading...
      </div>
    );
  }

  if (files.length === 0) {
    return (
      <div style={{ padding: '20px', textAlign: 'center', color: '#888' }}>
        Empty folder
      </div>
    );
  }

  return (
    <Table
      data={data}
      columns={columns}
      selection={selection}
      onSelect={handleSelect}
      onItemDoubleClick={handleRowDoubleClick}
      selectable
      draggable={false}
      getItemKey={(item) => item.path}
    />
  );
}

import List from '@jetbrains/ring-ui/components/list/list';
import type { SidebarItem } from '../types';

interface SidebarProps {
  currentPath: string;
  onNavigate: (path: string) => void;
  homeDir: string;
}

export function Sidebar({ currentPath, onNavigate, homeDir }: SidebarProps) {
  const favorites: SidebarItem[] = [
    { name: 'Desktop', path: `${homeDir}/Desktop`, icon: '🖥️' },
    { name: 'Documents', path: `${homeDir}/Documents`, icon: '📄' },
    { name: 'Downloads', path: `${homeDir}/Downloads`, icon: '⬇️' },
    { name: 'Applications', path: '/Applications', icon: '📦' },
  ];

  const locations: SidebarItem[] = [
    { name: 'Home', path: homeDir, icon: '🏠' },
    { name: 'Root', path: '/', icon: '💻' },
  ];

  const createListData = (items: SidebarItem[]) =>
    items.map(item => ({
      key: item.path,
      label: `${item.icon}  ${item.name}`,
      rgItemType: List.ListProps.Type.ITEM,
      onClick: () => onNavigate(item.path),
      className: currentPath === item.path ? 'selected' : '',
    }));

  return (
    <div className="sidebar">
      <div className="sidebar-section">
        <div className="sidebar-header">Favorites</div>
        <List
          data={createListData(favorites)}
          shortcuts={false}
          compact
        />
      </div>

      <div className="sidebar-section">
        <div className="sidebar-header">Locations</div>
        <List
          data={createListData(locations)}
          shortcuts={false}
          compact
        />
      </div>
    </div>
  );
}

