import Button from '@jetbrains/ring-ui/components/button/button';
import ButtonGroup from '@jetbrains/ring-ui/components/button-group/button-group';
import ChevronLeft from '@jetbrains/icons/chevron-left';
import ChevronRight from '@jetbrains/icons/chevron-right';

interface PathBarProps {
  currentPath: string;
  onNavigateUp: () => void;
  canGoBack: boolean;
  canGoForward: boolean;
  onGoBack?: () => void;
  onGoForward?: () => void;
}

export function PathBar({
  currentPath,
  onNavigateUp,
  canGoBack,
  canGoForward,
  onGoBack,
  onGoForward,
}: PathBarProps) {
  const pathParts = currentPath.split('/').filter(Boolean);

  return (
    <div className="path-bar">
      <div className="path-bar-nav">
        <ButtonGroup>
          <Button
            icon={ChevronLeft}
            disabled={!canGoBack}
            onClick={onGoBack}
            title="Go back"
          />
          <Button
            icon={ChevronRight}
            disabled={!canGoForward}
            onClick={onGoForward}
            title="Go forward"
          />
        </ButtonGroup>
      </div>

      <div className="path-bar-breadcrumb">
        {pathParts.map((part, index) => (
          <span key={index} className="path-part">
            {index > 0 && <span className="path-separator">/</span>}
            <span className="path-name">{part}</span>
          </span>
        ))}
      </div>
    </div>
  );
}

import { useEffect, useState, useCallback } from 'react';
import { homeDir } from '@tauri-apps/api/path';
import { open } from '@tauri-apps/plugin-opener';
import { useFileSystem } from './hooks/useFileSystem';
import { Sidebar } from './components/Sidebar';
import { FileList } from './components/FileList';
import { PathBar } from './components/PathBar';
import { Terminal } from './components/Terminal';
import type { FileEntry } from './types';

import '@jetbrains/ring-ui/components/style.css';
import './styles/app.css';

export default function App() {
  const [homeDirPath, setHomeDirPath] = useState('');
  const [history, setHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const [terminalKey, setTerminalKey] = useState(0);

  const {
    currentPath,
    files,
    loading,
    navigateTo,
    setCurrentPath,
  } = useFileSystem();

  // Initialize with home directory
  useEffect(() => {
    homeDir().then((home) => {
      setHomeDirPath(home);
      navigateTo(home);
      setHistory([home]);
      setHistoryIndex(0);
    });
  }, []);

  const handleNavigate = useCallback((path: string) => {
    navigateTo(path);

    // Update history
    const newHistory = history.slice(0, historyIndex + 1);
