import { useEffect, useState, useCallback } from 'react';
import { homeDir } from '@tauri-apps/api/path';
import { open } from '@tauri-apps/plugin-opener';
import { useFileSystem } from './hooks/useFileSystem';
import { Sidebar } from './components/Sidebar';
import { FileList } from './components/FileList';
import { PathBar } from './components/PathBar';
import { Terminal } from './components/Terminal';
import type { FileEntry } from './types';

import '@jetbrains/ring-ui/components/style.css';
import './styles/app.css';

export default function App() {
  const [homeDirPath, setHomeDirPath] = useState('');
  const [history, setHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const [terminalKey, setTerminalKey] = useState(0);

  const {
    currentPath,
    files,
    loading,
    navigateTo,
  } = useFileSystem();

  // Initialize with home directory
  useEffect(() => {
    homeDir().then((home) => {
      setHomeDirPath(home);
      navigateTo(home);
      setHistory([home]);
      setHistoryIndex(0);
    });
  }, []);

  const handleNavigate = useCallback((path: string) => {
    navigateTo(path);

    // Update history
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(path);
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  }, [navigateTo, history, historyIndex]);

  const handleFileOpen = useCallback((file: FileEntry) => {
    if (file.isDirectory) {
      handleNavigate(file.path);
    } else {
      // Open file with default app
      open(file.path);
    }
  }, [handleNavigate]);

  const handleGoBack = useCallback(() => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      setHistoryIndex(newIndex);
      navigateTo(history[newIndex]);
    }
  }, [history, historyIndex, navigateTo]);

  const handleGoForward = useCallback(() => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      setHistoryIndex(newIndex);
      navigateTo(history[newIndex]);
    }
  }, [history, historyIndex, navigateTo]);

  const handleNavigateUp = useCallback(() => {
    const parentPath = currentPath.split('/').slice(0, -1).join('/') || '/';
    handleNavigate(parentPath);
  }, [currentPath, handleNavigate]);

  const handleTerminalDirectoryChange = useCallback((newPath: string) => {
    if (newPath !== currentPath) {
      handleNavigate(newPath);
    }
  }, [currentPath, handleNavigate]);

  if (!homeDirPath) {
    return <div className="loading">Loading...</div>;
  }

  return (
    <div className="app">
      <div className="toolbar">
        <PathBar
          currentPath={currentPath}
          onNavigateUp={handleNavigateUp}
          canGoBack={historyIndex > 0}
          canGoForward={historyIndex < history.length - 1}
          onGoBack={handleGoBack}
          onGoForward={handleGoForward}
        />
      </div>

      <div className="main-content">
        <div className="sidebar-container">
          <Sidebar
            currentPath={currentPath}
            onNavigate={handleNavigate}
            homeDir={homeDirPath}
          />
        </div>

        <div className="file-list-container">
          <FileList
            files={files}
            loading={loading}
            onFileOpen={handleFileOpen}
          />
        </div>

        <div className="terminal-container">
          <div className="terminal-header">
            <span className="terminal-path">{currentPath}</span>
          </div>
          <Terminal
            key={terminalKey}
            currentPath={currentPath}
            onDirectoryChange={handleTerminalDirectoryChange}
          />
        </div>
      </div>
    </div>
  );
}

:root {
  --bg-color: #1e1e1e;
  --sidebar-bg: #252526;
  --toolbar-bg: #333333;
  --border-color: #3c3c3c;
  --text-color: #cccccc;
  --text-secondary: #888888;
  --accent-color: #0078d4;
  --hover-bg: #2a2d2e;
  --selected-bg: #094771;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html, body, #root {
  height: 100%;
  width: 100%;
  overflow: hidden;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Text', 'Segoe UI', Roboto, sans-serif;
  font-size: 13px;
  color: var(--text-color);
  background: var(--bg-color);
}

.loading {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
  color: var(--text-secondary);
}

.app {
  display: flex;
  flex-direction: column;
  height: 100%;
  background: var(--bg-color);
}

/* Toolbar */
.toolbar {
  flex-shrink: 0;
  height: 52px;
  background: var(--toolbar-bg);
  border-bottom: 1px solid var(--border-color);
  display: flex;
  align-items: center;
  padding: 0 12px;
  -webkit-app-region: drag;
}

.toolbar button {
  -webkit-app-region: no-drag;
}

/* Path Bar */
.path-bar {
  display: flex;
  align-items: center;
  gap: 16px;
  width: 100%;
}

.path-bar-nav {
  flex-shrink: 0;
}

.path-bar-breadcrumb {
  display: flex;
  align-items: center;
  background: var(--bg-color);
  border-radius: 6px;
  padding: 6px 12px;
  font-size: 12px;
  overflow: hidden;
  flex: 1;
}

.path-part {
  display: flex;
  align-items: center;
}

.path-separator {
  margin: 0 6px;
  color: var(--text-secondary);
}

.path-name {
  color: var(--text-color);
}

/* Main Content */
.main-content {
  display: flex;
  flex: 1;
  overflow: hidden;
}

/* Sidebar */
.sidebar-container {
  width: 200px;
  flex-shrink: 0;
  background: var(--sidebar-bg);
  border-right: 1px solid var(--border-color);
  overflow-y: auto;
}

.sidebar {
  padding: 8px 0;
}

.sidebar-section {
  margin-bottom: 16px;
}

.sidebar-header {
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  color: var(--text-secondary);
  padding: 8px 16px 4px;
  letter-spacing: 0.5px;
}

/* File List */
.file-list-container {
  flex: 1;
  overflow: auto;
  background: var(--bg-color);
}

/* Terminal */
.terminal-container {
  width: 400px;
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  border-left: 1px solid var(--border-color);
  background: #1e1e1e;
}

.terminal-header {
  flex-shrink: 0;
  height: 32px;
  display: flex;
  align-items: center;
  padding: 0 12px;
  background: var(--toolbar-bg);
  border-bottom: 1px solid var(--border-color);
}

.terminal-path {
  font-size: 11px;
  color: var(--text-secondary);
  font-family: 'SF Mono', Menlo, Monaco, monospace;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* Ring UI overrides for dark theme */
.ring-ui-theme-dark {
  --ring-content-background-color: var(--bg-color);
  --ring-popup-background-color: var(--sidebar-bg);
  --ring-text-color: var(--text-color);
  --ring-secondary-color: var(--text-secondary);
  --ring-line-color: var(--border-color);
  --ring-borders-color: var(--border-color);
}

/* Table styles */
[class*="ring-table"] {
  background: transparent !important;
}

[class*="ring-table"] th {
  background: var(--toolbar-bg) !important;
  color: var(--text-secondary) !important;
  font-weight: 500 !important;
  font-size: 11px !important;
  text-transform: uppercase !important;
  letter-spacing: 0.5px !important;
}

[class*="ring-table"] td {
  color: var(--text-color) !important;
  border-color: var(--border-color) !important;
}

[class*="ring-table"] tr:hover td {
  background: var(--hover-bg) !important;
}

[class*="ring-table"] tr[class*="checked"] td,
[class*="ring-table"] tr[class*="selected"] td {
  background: var(--selected-bg) !important;
}

/* List styles */
[class*="ring-list"] {
  background: transparent !important;
}

[class*="ring-list-item"]:hover {
  background: var(--hover-bg) !important;
}

[class*="ring-list-item"].selected {
  background: var(--selected-bg) !important;
}

/* Button styles */
[class*="ring-button"] {
  background: var(--toolbar-bg) !important;
  border-color: var(--border-color) !important;
  color: var(--text-color) !important;
}

[class*="ring-button"]:hover {
  background: var(--hover-bg) !important;
}

[class*="ring-button"]:disabled {
  opacity: 0.5;
}

/* Scrollbar */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--border-color);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: #555;
}

