     1→import { useEffect, useState, useCallback } from 'react';
     2→import { homeDir } from '@tauri-apps/api/path';
     3→import { open } from '@tauri-apps/plugin-opener';
     4→import { useFileSystem } from './hooks/useFileSystem';
     5→import { Sidebar } from './components/Sidebar';
     6→import { FileList } from './components/FileList';
     7→import { PathBar } from './components/PathBar';
     8→import { Terminal } from './components/Terminal';
     9→import type { FileEntry } from './types';
    10→
    11→import '@jetbrains/ring-ui/components/style.css';
    12→import './styles/app.css';
    13→
    14→export default function App() {
    15→  const [homeDirPath, setHomeDirPath] = useState('');
    16→  const [history, setHistory] = useState<string[]>([]);
    17→  const [historyIndex, setHistoryIndex] = useState(-1);
    18→  const [terminalKey, setTerminalKey] = useState(0);
    19→
    20→  const {
    21→    currentPath,
    22→    files,
    23→    loading,
    24→    navigateTo,
    25→  } = useFileSystem();
    26→
    27→  // Initialize with home directory
    28→  useEffect(() => {
    29→    homeDir().then((home) => {
    30→      setHomeDirPath(home);
    31→      navigateTo(home);
    32→      setHistory([home]);
    33→      setHistoryIndex(0);
    34→    });
    35→  }, []);
    36→
    37→  const handleNavigate = useCallback((path: string) => {
    38→    navigateTo(path);
    39→
    40→    // Update history
    41→    const newHistory = history.slice(0, historyIndex + 1);
    42→    newHistory.push(path);
    43→    setHistory(newHistory);
    44→    setHistoryIndex(newHistory.length - 1);
    45→  }, [navigateTo, history, historyIndex]);
    46→
    47→  const handleFileOpen = useCallback((file: FileEntry) => {
    48→    if (file.isDirectory) {
    49→      handleNavigate(file.path);
    50→    } else {
    51→      // Open file with default app
    52→      open(file.path);
    53→    }
    54→  }, [handleNavigate]);
    55→
    56→  const handleGoBack = useCallback(() => {
    57→    if (historyIndex > 0) {
    58→      const newIndex = historyIndex - 1;
    59→      setHistoryIndex(newIndex);
    60→      navigateTo(history[newIndex]);
    61→    }
    62→  }, [history, historyIndex, navigateTo]);
    63→
    64→  const handleGoForward = useCallback(() => {
    65→    if (historyIndex < history.length - 1) {
    66→      const newIndex = historyIndex + 1;
    67→      setHistoryIndex(newIndex);
    68→      navigateTo(history[newIndex]);
    69→    }
    70→  }, [history, historyIndex, navigateTo]);
    71→
    72→  const handleNavigateUp = useCallback(() => {
    73→    const parentPath = currentPath.split('/').slice(0, -1).join('/') || '/';
    74→    handleNavigate(parentPath);
    75→  }, [currentPath, handleNavigate]);
    76→
    77→  const handleTerminalDirectoryChange = useCallback((newPath: string) => {
    78→    if (newPath !== currentPath) {
    79→      handleNavigate(newPath);
    80→    }
    81→  }, [currentPath, handleNavigate]);
    82→
    83→  if (!homeDirPath) {
    84→    return <div className="loading">Loading...</div>;
    85→  }
    86→
    87→  return (
    88→    <div className="app">
    89→      <div className="toolbar">
    90→        <PathBar
    91→          currentPath={currentPath}
    92→          onNavigateUp={handleNavigateUp}
    93→          canGoBack={historyIndex > 0}
    94→          canGoForward={historyIndex < history.length - 1}
    95→          onGoBack={handleGoBack}
    96→          onGoForward={handleGoForward}
    97→        />
    98→      </div>
    99→
   100→      <div className="main-content">
   101→        <div className="sidebar-container">
   102→          <Sidebar
   103→            currentPath={currentPath}
   104→            onNavigate={handleNavigate}
   105→            homeDir={homeDirPath}
   106→          />
   107→        </div>
   108→
   109→        <div className="file-list-container">
   110→          <FileList
   111→            files={files}
