import List from '@jetbrains/ring-ui/components/list/list';
import type { SidebarItem } from '../types';

interface SidebarProps {
  currentPath: string;
  onNavigate: (path: string) => void;
  homeDir: string;
}

export function Sidebar({ currentPath, onNavigate, homeDir }: SidebarProps) {
  const favorites: SidebarItem[] = [
    { name: 'Desktop', path: `${homeDir}/Desktop`, icon: '🖥️' },
    { name: 'Documents', path: `${homeDir}/Documents`, icon: '📄' },
    { name: 'Downloads', path: `${homeDir}/Downloads`, icon: '⬇️' },
    { name: 'Applications', path: '/Applications', icon: '📦' },
  ];

  const locations: SidebarItem[] = [
    { name: 'Home', path: homeDir, icon: '🏠' },
    { name: 'Root', path: '/', icon: '💻' },
  ];

  const createListData = (items: SidebarItem[]) =>
    items.map(item => ({
      key: item.path,
      label: `${item.icon}  ${item.name}`,
      rgItemType: List.ListProps.Type.ITEM,
      onClick: () => onNavigate(item.path),
      className: currentPath === item.path ? 'selected' : '',
    }));

  return (
    <div className="sidebar">
      <div className="sidebar-section">
        <div className="sidebar-header">Favorites</div>
        <List
          data={createListData(favorites)}
          shortcuts={false}
          compact
        />
      </div>

      <div className="sidebar-section">
        <div className="sidebar-header">Locations</div>
        <List
          data={createListData(locations)}
          shortcuts={false}
          compact
        />
      </div>
    </div>
  );
}

