import { useState } from 'react';
import type { FileEntry } from '../types';

interface FileListProps {
  files: FileEntry[];
  loading: boolean;
  onFileOpen: (file: FileEntry) => void;
  onSelectionChange?: (selected: FileEntry[]) => void;
}

function formatBytes(bytes: number): string {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
}

function formatDate(date?: Date): string {
  if (!date) return '--';
  return date.toLocaleDateString('en-US', {
    day: 'numeric',
    month: 'short',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

export function FileList({ files, loading, onFileOpen }: FileListProps) {
  const [selectedPath, setSelectedPath] = useState<string | null>(null);

  if (loading) {
    return (
      <div className="file-list-empty">Loading...</div>
    );
  }

  if (files.length === 0) {
    return (
      <div className="file-list-empty">Empty folder</div>
    );
  }

  return (
    <div className="file-list">
      <div className="file-list-header">
        <span className="col-name">Name</span>
        <span className="col-date">Date Modified</span>
        <span className="col-size">Size</span>
      </div>
      <div className="file-list-body">
        {files.map(file => (
          <div
            key={file.path}
            className={`file-row ${selectedPath === file.path ? 'selected' : ''}`}
            onClick={() => setSelectedPath(file.path)}
            onDoubleClick={() => onFileOpen(file)}
          >
            <span className="col-name">
              <span className="file-icon">{file.isDirectory ? '📁' : '📄'}</span>
              {file.name}
            </span>
            <span className="col-date">{formatDate(file.modifiedAt)}</span>
            <span className="col-size">{file.isDirectory ? '--' : formatBytes(file.size || 0)}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

import type { SidebarItem } from '../types';

interface SidebarProps {
  currentPath: string;
  onNavigate: (path: string) => void;
  homeDir: string;
}

export function Sidebar({ currentPath, onNavigate, homeDir }: SidebarProps) {
  const favorites: SidebarItem[] = [
    { name: 'Desktop', path: `${homeDir}/Desktop`, icon: '🖥️' },
    { name: 'Documents', path: `${homeDir}/Documents`, icon: '📄' },
    { name: 'Downloads', path: `${homeDir}/Downloads`, icon: '⬇️' },
    { name: 'Applications', path: '/Applications', icon: '📦' },
  ];

  const locations: SidebarItem[] = [
    { name: 'Home', path: homeDir, icon: '🏠' },
    { name: 'Root', path: '/', icon: '💻' },
  ];

  return (
    <div className="sidebar">
      <div className="sidebar-section">
        <div className="sidebar-header">Favorites</div>
        <ul className="sidebar-list">
          {favorites.map(item => (
            <li
              key={item.path}
              className={`sidebar-item ${currentPath === item.path ? 'active' : ''}`}
              onClick={() => onNavigate(item.path)}
            >
              <span className="sidebar-icon">{item.icon}</span>
              <span className="sidebar-name">{item.name}</span>
            </li>
          ))}
        </ul>
      </div>

      <div className="sidebar-section">
        <div className="sidebar-header">Locations</div>
        <ul className="sidebar-list">
          {locations.map(item => (
            <li
              key={item.path}
              className={`sidebar-item ${currentPath === item.path ? 'active' : ''}`}
              onClick={() => onNavigate(item.path)}
            >
              <span className="sidebar-icon">{item.icon}</span>
              <span className="sidebar-name">{item.name}</span>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

interface PathBarProps {
  currentPath: string;
  onNavigateUp: () => void;
  canGoBack: boolean;
  canGoForward: boolean;
  onGoBack?: () => void;
  onGoForward?: () => void;
}

export function PathBar({
  currentPath,
  canGoBack,
  canGoForward,
  onGoBack,
  onGoForward,
}: PathBarProps) {
  const pathParts = currentPath.split('/').filter(Boolean);

  return (
    <div className="path-bar">
      <div className="path-bar-nav">
        <button
          className="nav-btn"
          disabled={!canGoBack}
          onClick={onGoBack}
          title="Go back"
        >
          ‹
        </button>
        <button
          className="nav-btn"
          disabled={!canGoForward}
          onClick={onGoForward}
          title="Go forward"
        >
          ›
        </button>
      </div>

      <div className="path-bar-breadcrumb">
        {pathParts.map((part, index) => (
          <span key={index} className="path-part">
            {index > 0 && <span className="path-separator">/</span>}
            <span className="path-name">{part}</span>
          </span>
        ))}
      </div>
    </div>
  );
}

