import { useEffect, useState, useCallback } from 'react';
import { homeDir } from '@tauri-apps/api/path';
import { open } from '@tauri-apps/plugin-opener';
import { useFileSystem } from './hooks/useFileSystem';
import { Sidebar } from './components/Sidebar';
import { FileList } from './components/FileList';
import { PathBar } from './components/PathBar';
import { Terminal } from './components/Terminal';
import type { FileEntry } from './types';

import '@jetbrains/ring-ui/components/global/global.css';
import '@jetbrains/ring-ui/components/global/variables.css';
import '@jetbrains/ring-ui/components/global/variables_dark.css';
import './styles/app.css';

export default function App() {
  const [homeDirPath, setHomeDirPath] = useState('');
  const [history, setHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const [terminalKey, setTerminalKey] = useState(0);

  const {
    currentPath,
    files,
    loading,
    navigateTo,
  } = useFileSystem();

  // Initialize with home directory
  useEffect(() => {
    homeDir().then((home) => {
      setHomeDirPath(home);
      navigateTo(home);
      setHistory([home]);
      setHistoryIndex(0);
    });
  }, []);

  const handleNavigate = useCallback((path: string) => {
    navigateTo(path);

    // Update history
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(path);
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  }, [navigateTo, history, historyIndex]);

  const handleFileOpen = useCallback((file: FileEntry) => {
    if (file.isDirectory) {
      handleNavigate(file.path);
    } else {
      // Open file with default app
      open(file.path);
    }
  }, [handleNavigate]);

  const handleGoBack = useCallback(() => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      setHistoryIndex(newIndex);
      navigateTo(history[newIndex]);
    }
  }, [history, historyIndex, navigateTo]);

  const handleGoForward = useCallback(() => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      setHistoryIndex(newIndex);
      navigateTo(history[newIndex]);
    }
  }, [history, historyIndex, navigateTo]);

  const handleNavigateUp = useCallback(() => {
    const parentPath = currentPath.split('/').slice(0, -1).join('/') || '/';
    handleNavigate(parentPath);
  }, [currentPath, handleNavigate]);

  const handleTerminalDirectoryChange = useCallback((newPath: string) => {
    if (newPath !== currentPath) {
      handleNavigate(newPath);
    }
  }, [currentPath, handleNavigate]);

  if (!homeDirPath) {
    return <div className="loading">Loading...</div>;
  }

  return (
    <div className="app">
      <div className="toolbar">
        <PathBar
          currentPath={currentPath}
          onNavigateUp={handleNavigateUp}
          canGoBack={historyIndex > 0}
          canGoForward={historyIndex < history.length - 1}
          onGoBack={handleGoBack}
          onGoForward={handleGoForward}
        />
      </div>

      <div className="main-content">
        <div className="sidebar-container">
          <Sidebar
            currentPath={currentPath}
            onNavigate={handleNavigate}
            homeDir={homeDirPath}
          />
        </div>

        <div className="file-list-container">
          <FileList
            files={files}
            loading={loading}
            onFileOpen={handleFileOpen}
          />
        </div>

        <div className="terminal-container">
          <div className="terminal-header">
            <span className="terminal-path">{currentPath}</span>
          </div>
          <Terminal
            key={terminalKey}
            currentPath={currentPath}
            onDirectoryChange={handleTerminalDirectoryChange}
          />
        </div>
      </div>
    </div>
  );
}

