import { useEffect, useRef, useCallback } from 'react';
import { Terminal as XTerm } from '@xterm/xterm';
import { FitAddon } from '@xterm/addon-fit';
import { WebLinksAddon } from '@xterm/addon-web-links';
import { Command } from '@tauri-apps/plugin-shell';
import '@xterm/xterm/css/xterm.css';

interface TerminalProps {
  currentPath: string;
  onDirectoryChange?: (newPath: string) => void;
}

export function Terminal({ currentPath, onDirectoryChange }: TerminalProps) {
  const terminalRef = useRef<HTMLDivElement>(null);
  const xtermRef = useRef<XTerm | null>(null);
  const fitAddonRef = useRef<FitAddon | null>(null);
  const shellRef = useRef<Awaited<ReturnType<typeof Command.create>> | null>(null);
  const currentPathRef = useRef(currentPath);

  // Keep currentPath ref updated
  useEffect(() => {
    currentPathRef.current = currentPath;
  }, [currentPath]);

  const initTerminal = useCallback(async () => {
    if (!terminalRef.current || xtermRef.current) return;

    // Create terminal
    const xterm = new XTerm({
      theme: {
        background: '#1e1e1e',
        foreground: '#d4d4d4',
        cursor: '#d4d4d4',
        cursorAccent: '#1e1e1e',
        selectionBackground: '#264f78',
        black: '#000000',
        red: '#cd3131',
        green: '#0dbc79',
        yellow: '#e5e510',
        blue: '#2472c8',
        magenta: '#bc3fbc',
        cyan: '#11a8cd',
        white: '#e5e5e5',
        brightBlack: '#666666',
        brightRed: '#f14c4c',
        brightGreen: '#23d18b',
        brightYellow: '#f5f543',
        brightBlue: '#3b8eea',
        brightMagenta: '#d670d6',
        brightCyan: '#29b8db',
        brightWhite: '#ffffff',
      },
      fontFamily: '"SF Mono", Menlo, Monaco, "Courier New", monospace',
      fontSize: 13,
      lineHeight: 1.2,
      cursorBlink: true,
      cursorStyle: 'block',
      scrollback: 10000,
      allowProposedApi: true,
    });

    // Add addons
    const fitAddon = new FitAddon();
    const webLinksAddon = new WebLinksAddon();
    xterm.loadAddon(fitAddon);
    xterm.loadAddon(webLinksAddon);

    // Open terminal
    xterm.open(terminalRef.current);
    fitAddon.fit();

    xtermRef.current = xterm;
    fitAddonRef.current = fitAddon;

    // Start shell
    try {
      const shell = await Command.create('exec-sh', ['-c', `cd "${currentPath}" && exec $SHELL -l`], {
        cwd: currentPath,
        env: {
          TERM: 'xterm-256color',
        },
      });

      shell.stdout.on('data', (data) => {
        xterm.write(data);
      });

      shell.stderr.on('data', (data) => {
        xterm.write(data);
      });

      shell.on('close', () => {
        xterm.write('\r\n[Process exited]\r\n');
      });

      // Handle user input
      xterm.onData((data) => {
        shell.stdin?.write(data);
      });

      await shell.spawn();
      shellRef.current = shell;

    } catch (err) {
      console.error('Failed to start shell:', err);
      xterm.write(`Error: ${err}\r\n`);
    }

    // Handle resize
    const resizeObserver = new ResizeObserver(() => {
      fitAddon.fit();
    });
    resizeObserver.observe(terminalRef.current);

    return () => {
      resizeObserver.disconnect();
    };
  }, [currentPath]);

  useEffect(() => {
    initTerminal();

    return () => {
      shellRef.current?.kill();
      xtermRef.current?.dispose();
      xtermRef.current = null;
      shellRef.current = null;
    };
  }, []);

  // Send cd command when path changes externally
  useEffect(() => {
    if (shellRef.current && xtermRef.current && currentPath !== currentPathRef.current) {
      shellRef.current.stdin?.write(`cd "${currentPath}"\n`);
    }
  }, [currentPath]);

  return (
    <div
      ref={terminalRef}
      style={{
        width: '100%',
        height: '100%',
        backgroundColor: '#1e1e1e',
        padding: '8px',
      }}
    />
  );
}

