import { useState, useMemo } from 'react';
import Table from '@jetbrains/ring-ui-built/components/table/table';
import Selection from '@jetbrains/ring-ui-built/components/table/selection';
import type { FileEntry } from '../types';

interface FileListProps {
  files: FileEntry[];
  loading: boolean;
  onFileOpen: (file: FileEntry) => void;
  onSelectionChange?: (selected: FileEntry[]) => void;
}

function formatBytes(bytes: number): string {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
}

function formatDate(date?: Date): string {
  if (!date) return '--';
  return date.toLocaleDateString('en-US', {
    day: 'numeric',
    month: 'short',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

const columns = [
  {
    id: 'name',
    title: 'Name',
    getValue: (item: FileEntry) => item.name,
  },
  {
    id: 'modified',
    title: 'Date Modified',
    getValue: (item: FileEntry) => formatDate(item.modifiedAt),
  },
  {
    id: 'size',
    title: 'Size',
    getValue: (item: FileEntry) => item.isDirectory ? '--' : formatBytes(item.size || 0),
  },
];

export function FileList({ files, loading, onFileOpen }: FileListProps) {
  const selection = useMemo(() => new Selection({
    data: files,
    isItemSelectable: () => true,
  }), [files]);

  const data = useMemo(() => files.map(file => ({
    ...file,
    id: file.path,
    name: `${file.isDirectory ? '📁' : '📄'} ${file.name}`,
  })), [files]);

  if (loading) {
    return (
      <div className="file-list-empty">Loading...</div>
    );
  }

  if (files.length === 0) {
    return (
      <div className="file-list-empty">Empty folder</div>
    );
  }

  return (
    <div className="file-list">
      <Table
        data={data}
        columns={columns}
        selection={selection}
        onSelect={(selected) => {
          if (selected.getSelected().length === 1) {
            const file = selected.getSelected()[0];
            // Find original file entry
            const original = files.find(f => f.path === file.id);
            if (original) {
              onFileOpen(original);
            }
          }
        }}
        selectable
        stickyHeader
      />
    </div>
  );
}

