   581→        throw new Error("Window control requires nutjs to be fully loaded");
   582→      }
   583→    }
   584→
   585→    let targetWindow: any;
   586→
   587→    if (windowTitle) {
   588→      const windows = await getWindows();
   589→      targetWindow = await Promise.all(
   590→        windows.map(async (win: any) => ({
   591→          window: win,
   592→          title: await win.getTitle(),
   593→        }))
   594→      ).then(
   595→        (windowsWithTitles) =>
   596→          windowsWithTitles.find((w) => w.title.includes(windowTitle))?.window
   597→      );
   598→
   599→      if (!targetWindow) {
   600→        throw new Error(
   601→          `Window with title containing "${windowTitle}" not found`
   602→        );
   603→      }
   604→    } else {
   605→      targetWindow = await getActiveWindow();
   606→    }
   607→
   608→    const windowName = await targetWindow.getTitle();
   609→
   610→    switch (action) {
   611→      case "focus":
   612→        await targetWindow.focus();
   613→        return `Focused window: "${windowName}"`;
   614→
   615→      case "move":
   616→        if (x === undefined || y === undefined) {
   617→          throw new Error("Move action requires x and y coordinates");
   618→        }
   619→        await targetWindow.move(new Point(x, y));
   620→        return `Moved window "${windowName}" to (${x}, ${y})`;
   621→
   622→      case "resize":
   623→        if (width === undefined || height === undefined) {
   624→          throw new Error("Resize action requires width and height");
   625→        }
   626→        await targetWindow.resize(new Size(width, height));
   627→        return `Resized window "${windowName}" to ${width}x${height}`;
   628→
   629→      case "minimize":
   630→        await targetWindow.minimize();
   631→        return `Minimized window: "${windowName}"`;
   632→
   633→      case "restore":
   634→        await targetWindow.restore();
   635→        return `Restored window: "${windowName}"`;
   636→
   637→      default:
   638→        throw new Error(`Unknown action: ${action}`);
   639→    }
   640→  },
   641→});
   642→
   643→// ============== ADVANCED AUTOMATION TOOLS ==============
   644→
   645→// Tool 17: Wait and Find on Screen
   646→server.addTool({
   647→  name: "waitForImage",
   648→  description: "Wait for an image to appear on screen and return its location.",
   649→  parameters: z.object({
   650→    imagePath: z.string().describe("Path to the template image file"),
   651→    timeoutMs: z.number().default(5000).describe("Timeout in milliseconds"),
   652→    confidence: z
   653→      .number()
   654→      .min(0)
   655→      .max(1)
   656→      .default(0.8)
   657→      .describe("Match confidence (0-1)"),
   658→  }),
   659→  execute: async ({ imagePath, timeoutMs, confidence }) => {
   660→    return `Image matching functionality requires additional setup. Would wait for image "${imagePath}" with confidence ${confidence} for ${timeoutMs}ms.`;
   661→  },
   662→});
   663→
   664→// Tool 18: Sleep/Delay
   665→server.addTool({
   666→  name: "sleep",
   667→  description: "Pause execution for a specified amount of time.",
   668→  parameters: z.object({
   669→    ms: z.number().describe("Time to sleep in milliseconds"),
   670→  }),
   671→  execute: async ({ ms }) => {
   672→    await new Promise((resolve) => setTimeout(resolve, ms));
   673→    return `Slept for ${ms} milliseconds`;
   674→  },
   675→});
   676→
   677→// Tool 19: Complex Mouse Path Movement
   678→server.addTool({
   679→  name: "mouseMovePath",
   680→  description: "Move mouse along a path of coordinates with smooth animation.",
   681→  parameters: z.object({
   682→    path: z
   683→      .array(z.number())
   684→      .describe(
   685→        "Array of coordinates to move through (alternating x,y values: [x1,y1,x2,y2,...])"
   686→      ),
   687→  }),
   688→  execute: async ({ path }) => {
   689→    requireNutjs();
   690→
   691→    // Validate that we have an even number of coordinates
   692→    if (path.length % 2 !== 0) {
   693→      throw new Error(
   694→        "Path array must contain an even number of values (alternating x,y coordinates)"
   695→      );
   696→    }
   697→
   698→    // Convert flat array to Point objects
   699→    const points: any[] = [];
   700→    for (let i = 0; i < path.length; i += 2) {
   701→      points.push(new Point(path[i], path[i + 1]));
   702→    }
   703→
   704→    await mouse.move(points);
   705→    return `Mouse moved along path with ${points.length} points`;
   706→  },
   707→});
   708→
   709→// Tool 20: System Key Combinations
   710→server.addTool({
   711→  name: "systemCommand",
   712→  description:
   713→    "Execute common system key combinations (copy, paste, undo, etc.).",
   714→  parameters: z.object({
   715→    command: z
   716→      .enum([
   717→        "copy",
   718→        "paste",
   719→        "cut",
   720→        "undo",
   721→        "redo",
   722→        "selectAll",
   723→        "save",
   724→        "quit",
   725→        "minimize",
   726→        "switchApp",
   727→        "newTab",
   728→        "closeTab",
   729→      ])
   730→      .describe("System command to execute"),
   731→  }),
   732→  execute: async ({ command }) => {
   733→    if (nutjsAvailable) {
   734→      const isMac = process.platform === "darwin";
   735→      const cmdKey = isMac ? Key.LeftSuper : Key.LeftControl;
   736→
   737→      switch (command) {
   738→        case "copy":
   739→          await keyboard.pressKey(cmdKey, Key.C);
   740→          await keyboard.releaseKey(cmdKey, Key.C);
   741→          return "Executed copy command";
   742→
   743→        case "paste":
   744→          await keyboard.pressKey(cmdKey, Key.V);
   745→          await keyboard.releaseKey(cmdKey, Key.V);
   746→          return "Executed paste command";
   747→
   748→        case "cut":
   749→          await keyboard.pressKey(cmdKey, Key.X);
   750→          await keyboard.releaseKey(cmdKey, Key.X);
   751→          return "Executed cut command";
   752→
   753→        case "undo":
   754→          await keyboard.pressKey(cmdKey, Key.Z);
   755→          await keyboard.releaseKey(cmdKey, Key.Z);
   756→          return "Executed undo command";
   757→
   758→        case "redo":
   759→          if (isMac) {
   760→            await keyboard.pressKey(cmdKey, Key.LeftShift, Key.Z);
   761→            await keyboard.releaseKey(cmdKey, Key.LeftShift, Key.Z);
   762→          } else {
   763→            await keyboard.pressKey(cmdKey, Key.Y);
   764→            await keyboard.releaseKey(cmdKey, Key.Y);
   765→          }
   766→          return "Executed redo command";
   767→
   768→        case "selectAll":
   769→          await keyboard.pressKey(cmdKey, Key.A);
   770→          await keyboard.releaseKey(cmdKey, Key.A);
   771→          return "Executed select all command";
   772→
   773→        case "save":
   774→          await keyboard.pressKey(cmdKey, Key.S);
   775→          await keyboard.releaseKey(cmdKey, Key.S);
   776→          return "Executed save command";
   777→
   778→        case "quit":
   779→          if (isMac) {
   780→            await keyboard.pressKey(cmdKey, Key.Q);
   781→            await keyboard.releaseKey(cmdKey, Key.Q);
   782→          } else {
   783→            await keyboard.pressKey(Key.LeftAlt, Key.F4);
   784→            await keyboard.releaseKey(Key.LeftAlt, Key.F4);
   785→          }
   786→          return "Executed quit command";
   787→
   788→        case "minimize":
   789→          if (isMac) {
   790→            await keyboard.pressKey(cmdKey, Key.M);
   791→            await keyboard.releaseKey(cmdKey, Key.M);
   792→          } else {
   793→            await keyboard.pressKey(Key.LeftSuper, Key.Down);
   794→            await keyboard.releaseKey(Key.LeftSuper, Key.Down);
   795→          }
   796→          return "Executed minimize command";
   797→
   798→        case "switchApp":
   799→          if (isMac) {
   800→            await keyboard.pressKey(cmdKey, Key.Tab);
   801→            await keyboard.releaseKey(cmdKey, Key.Tab);
   802→          } else {
   803→            await keyboard.pressKey(Key.LeftAlt, Key.Tab);
   804→            await keyboard.releaseKey(Key.LeftAlt, Key.Tab);
   805→          }
   806→          return "Executed switch app command";
   807→
   808→        case "newTab":
   809→          await keyboard.pressKey(cmdKey, Key.T);
   810→          await keyboard.releaseKey(cmdKey, Key.T);
   811→          return "Executed new tab command";
   812→
   813→        case "closeTab":
   814→          await keyboard.pressKey(cmdKey, Key.W);
   815→          await keyboard.releaseKey(cmdKey, Key.W);
   816→          return "Executed close tab command";
   817→
   818→        default:
   819→          throw new Error(`Unknown command: ${command}`);
   820→      }
   821→    } else {
   822→      // Fallback using AppleScript for macOS
   823→      const commandMap: { [key: string]: string } = {
   824→        copy: 'keystroke "c" using command down',
   825→        paste: 'keystroke "v" using command down',
   826→        cut: 'keystroke "x" using command down',
   827→        undo: 'keystroke "z" using command down',
   828→        redo: 'keystroke "z" using {command down, shift down}',
   829→        selectAll: 'keystroke "a" using command down',
   830→        save: 'keystroke "s" using command down',
   831→        quit: 'keystroke "q" using command down',
   832→        minimize: 'keystroke "m" using command down',
   833→        switchApp: "keystroke tab using command down",
   834→        newTab: 'keystroke "t" using command down',
   835→        closeTab: 'keystroke "w" using command down',
   836→      };
   837→
   838→      const script = commandMap[command];
   839→      if (script) {
   840→        child_process.execSync(
   841→          `osascript -e 'tell application "System Events" to ${script}'`
   842→        );
   843→        return `Executed ${command} command using AppleScript`;
   844→      } else {
   845→        throw new Error(`Unknown command: ${command}`);
   846→      }
   847→    }
   848→  },
   849→});
