    x: z.number().describe("Target horizontal coordinate (pixels)"),
    y: z.number().describe("Target vertical coordinate (pixels)"),
  }),
  execute: async ({ x, y }) => {
    requireNutjs();
    const currentPos = await mouse.getPosition();
    await mouse.drag([new Point(x, y)]);
